import { useState,useEffect } from "react";
import  axios  from 'axios';
export default function Index(){
    const [data,setData] = useState([]);
    const getData = async () => {
        const res = await axios.get("http://localhost:3003");
        setData(res.data);
        
    }
    useEffect(() => {
        console.log(data);
        getData();
    },[]);
    return (
        <>
       <center>
            <div className="kanban">
    <div className="column">
        <h3>À faire</h3>
        {todo.map(t => (
        <div key={t.id} className="task">
            <h4>{t.titre}</h4>
            <p>{t.description}</p>
        </div>
        ))}
    </div>

    <div className="column">
        <h3>En cours</h3>
        {inProgress.map(t => (
        <div key={t.id} className="task">
            <h4>{t.titre}</h4>
            <p>{t.description}</p>
        </div>
        ))}
    </div>

    <div className="column">
        <h3>Terminé</h3>
        {done.map(t => (
        <div key={t.id} className="task">
            <h4>{t.titre}</h4>
            <p>{t.description}</p>
        </div>
        ))}
    </div>
    </div>
       </center>
        </>
    )
}
